ď»żINSERT INTO public.photos VALUES (24344, 'S. Juan de los Panetes 1930', '"Iglesia de San Juan. La Torre". La nueva fabrica de la antigua iglesia templaria de San Juan, en el primer cuarto del siglo XVIII, supuso la reorientaciâ”śâ”‚n de su planta, la construcciâ”śâ”‚n de su caracterâ”śÂˇstica torrecilla, y de un arco de acceso a la parroquia, denominado de San Juan, desde la calle de los Agustinos. En la imagen, el arco presenta en su parte superior una hornacida votiva barroca. La diâ”śĂ­fana y soleada plaza de Huesca, previa al arco, era consecuencia del derribo de la antigua manzana de edificios entre las calles de Agustinos, Danzas, y San Juan de los Panetes.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65733800, -0.88108900, '0101000020E6100000E6B0FB8EE131ECBF8335CEA623D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688645699.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688645699.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688645699/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
