INSERT INTO public.photos VALUES (24354, 'Labordeta 1986', 'Foto: Rogelio Allepuz, febrero de 1986. Josâ”śÂ® Antonio Labordeta posa ante la iglesia de San Juan de los Panetes de Zaragoza. Fuente: El Periâ”śâ”‚dico de Aragâ”śâ”‚n', 1986, 1986, 1986, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65730100, -0.88100600, '0101000020E6100000868DB27E3331ECBF65506D7022D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14914840931.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14914840931.webp', 'https://www.flickr.com/photos/zaragozaantigua/14914840931/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24360, 'San Juan de los Panetes 1933', 'Entorno de la iglesia de San Juan de los Panetes en diciembre de 1933, tras el incendio provocado en su interior durante unos disturbios. Las tropas del Ejâ”śÂ®rcito de la Repâ”śâ•‘blica, desplegadas, montan guardia para prevenciâ”śâ”‚n de nuevos atentados. Fuente visual: Heraldo de Aragâ”śâ”‚n', 1933, 1933, 1933, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65729700, -0.88130000, '0101000020E6100000A4DFBE0E9C33ECBF2461DF4E22D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15000690245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15000690245.webp', 'https://www.flickr.com/photos/zaragozaantigua/15000690245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24364, 'Pilar y Panetes c.1915', 'AHPZ. Juan Mora Insa. SF "Zaragoza. Vista del Pilar por la ribera." Ribera derecha, con las traseras de San Juan de los Panetes detrâ”śĂ­s del â”śĂ­rbol en primerâ”śÂˇsimo plano. Un par de carros aparcados, y un paisano buscando gamusinos.', 1915, 1915, 1915, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65792400, -0.88119100, '0101000020E6100000F5F1D077B732ECBF73A087DA36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15174618346.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15174618346.webp', 'https://www.flickr.com/photos/zaragozaantigua/15174618346/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24366, 'Puerta de San Ildefonso c.1900', '"Puerta de San Ildefonso", Antonio Callaved, 2010. Puerta de San Ildefonso o de la Triperâ”śÂˇa, construida en ladrillo y abierta al paseo de la Ribera, en la zona de San Juan de los Panetes (izquierda) y el Torreâ”śâ”‚n de la Zuda (a su derecha). Derribada en 1904. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65774400, -0.88172000, '0101000020E6100000F35487DC0C37ECBFF39194F430D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15275841691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15275841691.webp', 'https://www.flickr.com/photos/zaragozaantigua/15275841691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24373, 'San Juan de los Panetes aâ”śâ–’os 30', 'Aspecto de la calle Agustinos, conducente al acceso a la iglesia parroquial de San Juan de los Panetes. Fuente visual: Ascensiâ”śâ”‚n Hernâ”śĂ­ndez Martâ”śÂˇnez, "De restauraciones, demoliciones y otros debates sobre el patrimonio monumental zaragozano del siglo XX", IFC, 2008.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15686649272.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15686649272.webp', 'https://www.flickr.com/photos/zaragozaantigua/15686649272/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24377, 'San Juan de los Panetes 1930', 'A mediados del siglo XIX comenzâ”śâ”‚ un largo, complejo y discutido proceso de transformaciâ”śâ”‚n del antiguo y enorme conjunto de la "iglesia de San Juan de los Panetes de la Religiâ”śâ”‚n de San Juan de Jerusalâ”śÂ®n, y la Casa y Palacio de la Castellanâ”śÂˇa de Amposta". La imagen captura la portada y torre de la iglesia resultantes de la nueva fâ”śĂ­brica de 1720. En esos momentos se estaba procediendo a derribar algunas de las dependencias del antiguo convento, utilizado en â”śâ•‘ltima instancia por la Congregaciâ”śâ”‚n de Adoratrices Esclavas del Santâ”śÂˇsimo Sacramento y de la Caridad. El acceso a la iglesia estâ”śĂ­ al mismo nivel que la calle, y se accede por el pequeâ”śâ–’o callejâ”śâ”‚n de la imagen, desde la calle de los Agustinos, y tambiâ”śÂ®n desde la plaza de San Antâ”śâ”‚n, fuera de plano, y a la derecha. Tras dâ”śÂ®cadas de actuaciones, al final la iglesia quedâ”śâ”‚ exenta y elevada respecto del terreno que la rodea, el Torreâ”śâ”‚n de la Sudda fue reinventado, y volvieron a ver la luz tres torreones y un buen pedazo de la antigua muralla romana, tanto la original, como la aâ”śâ–’adida en el siglo III de la era.', 1930, 1930, 1930, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19442963681.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19442963681.webp', 'https://www.flickr.com/photos/zaragozaantigua/19442963681/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24386, 'San Juan de los Panetes 1972', 'Torreâ”śâ”‚n de la Zuda e iglesia de San Juan de los Panetes. Al fondo, el antiguo colegio Valentâ”śÂˇn Zabala. Fuente visual: Foto Leonardo Pâ”śÂ®rez Obis, donada por â”śĂĽngel Hernâ”śĂ­ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23146350105.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23146350105.webp', 'https://www.flickr.com/photos/zaragozaantigua/23146350105/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24390, 'San Juan de los Panetes aâ”śâ–’os 30', 'Portada y torre de la iglesia de San Juan de los Panetes, desde las ruinas de las casas adosadas a las murallas romanas. Fuente: www.skyscrapercity.com/', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24759743661.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24759743661.webp', 'https://www.flickr.com/photos/zaragozaantigua/24759743661/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24411, 'San Juan de los Panetes aâ”śâ–’os 30', 'Acuarela de Ambrosio Ruste representando la portada de la iglesia de San Juan de los Panetes. Fuente: Lâ”śĂ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65746300, -0.88131100, '0101000020E61000009E5C5320B333ECBF3FAA61BF27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32317797271.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32317797271.webp', 'https://www.flickr.com/photos/zaragozaantigua/32317797271/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24412, 'Plaza de Huesca aâ”śâ–’os 30', 'Acuarela de Ambrosio Ruste, que muestra la torre de San Juan de los Panetes desde la plaza de Huesca, y el arco de San Juan. Fuente: Lâ”śĂ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65734300, -0.88091400, '0101000020E61000005AD5928E7230ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32399025396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32399025396.webp', 'https://www.flickr.com/photos/zaragozaantigua/32399025396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24661, 'Torreâ”śâ”‚n de la Zuda 1972', 'Ayuntamiento de Zaragoza/Gerardo Sancho Ramo. Noviembre 1972. El Torreâ”śâ”‚n de la Zuda se levantâ”śâ”‚ sobre la torre del homenaje del alcâ”śĂ­zar palacio de La Sudda, La Zuda o Azuda, construido a su vez sobre uno de los torreones de la muralla romana. La Sudda fue la residencia fortificada de los gobernadores musulmanes de la taifa de Sarakusta, hasta que trasladaron su residencia oficial al palacio de la Aljaferâ”śÂˇa. Tras la conquista cristina, fue residencia de los monarcas aragoneses hasta el siglo XIII, en que tambiâ”śÂ®n se orientaron hacia la Aljaferâ”śÂˇa. El torreâ”śâ”‚n fue reedificado en la segunda mitad del siglo XVI. La imagen actual del torreâ”śâ”‚n responde a la restauraciâ”śâ”‚n llevada a cabo por Francisco Iâ”śâ–’iguez entre 1946 y 1952, quien dio prioridad a las formas renacentistas sobre las anteriores, en coherencia con la lâ”śÂˇnea historicista-regionalista de la arquitectura del Râ”śÂ®gimen franquista en esos momentos. En la imagen de conjunto, el Torreâ”śâ”‚n, las murallas romanas, y el pozo que en la penâ”śâ•‘ltima intervenciâ”śâ”‚n fue llevado al Parque Grande.', 1972, 1972, 1972, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65739300, -0.88151400, '0101000020E6100000A7EA1ED95C35ECBF46CF2D7425D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710521427.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710521427.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710521427/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24662, 'Puerta de San Ildefonso 1904', 'Colecciâ”śâ”‚n Rafael Esteban. Foto: Agustâ”śÂˇn Esteban, 1904. Vista cercana de la puerta de San Ildefonso o de la Triperâ”śÂˇa, tomada desde la calle de este nombre, a la orilla del Ebro. Hacia dentro, la calle Antonio Pâ”śÂ®rez hacia el Mercado, con el torreâ”śâ”‚n de la Zuda arriba a la izquierda. La puerta serâ”śÂˇa derribada ese mismo aâ”śâ–’o. En la puerta, un azulejo advierte que "EN ESTA CIUDAD NO SE TOLERA LA MENDICIDAD NI LA BLASFEMIA". Dicho queda.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65779400, -0.88163500, '0101000020E61000006649809A5A36ECBFA5C0029832D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14919914990.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14919914990.webp', 'https://www.flickr.com/photos/zaragozaantigua/14919914990/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24664, 'Embarcadero del Ebro c.1925', 'Imagen de las escaleras de acceso al servicio de barca que en este tramo del râ”śÂˇo permitâ”śÂˇa su paso. Al fondo, San Juan de los Panetes, el torreâ”śâ”‚n de la Zuda, la calle de Antonio Pâ”śÂ®rez conducente al Mercado Central, y el colegio Valentâ”śÂˇn Zabala. Fuente visual: Archivo Coyne, en "El Ebro y sus riberas", Ayuntamiento de Zaragoza.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65800400, -0.88137300, '0101000020E6100000207A52263534ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15121638044.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15121638044.webp', 'https://www.flickr.com/photos/zaragozaantigua/15121638044/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24665, 'San Juan de los Panetes 1927', '"Rodio" (Luis Pablo Sanz Lafita) dibuja con trazos modernos y atinados una visual de San Juan de los Panetes desde la inmediata ribera del Ebro, y la acompaâ”śâ–’a de un â”śĂ­rbol retorcido, una anciana crepuscular, un viejo "Ford", y un carro a la funerala. Hay nubes, sombras y claros para una composiciâ”śâ”‚n propia de un dâ”śÂˇa de difuntos, tanto para los que ya lo son, como para los que lo seremos. Fuente visual: "Aragâ”śâ”‚n : revista grâ”śĂ­fica de cultura aragonesa" (Aâ”śâ–’o III, Nâ”¬â•‘ 20, mayo 1927).', 1927, 1927, 1927, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65771500, -0.88075300, '0101000020E61000000D535BEA202FECBF598B4F0130D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15480634399.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15480634399.webp', 'https://www.flickr.com/photos/zaragozaantigua/15480634399/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24666, 'La Zuda 1987', 'Luis Mâ”śÂˇnguez. 1987. Desde el Torreâ”śâ”‚n de la Zuda, un vistazo al Suroeste, siguiendo la Avenida de Câ”śÂ®sar Augusto, por encima de los cubos ultrasemicirculares de la Murallas Romanas del s.III, la antigua plaza de Lanuza, el Mercado Central, hasta llegar a la câ”śâ•‘pula de Santiago el Mayor, al fondo. A su derecha, la iglesia de los Escolapios. Hegemonâ”śÂˇa espacial del trâ”śĂ­fico rodado, en movimiento, y aparcado. Solares en barbecho.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15667970199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15667970199.webp', 'https://www.flickr.com/photos/zaragozaantigua/15667970199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24667, 'Plaza de Huesca 1925', 'Miguel Faci Abad. 1920-1925. "Zaragoza. Antigua plaza Huesca ante la iglesia de San Juan de los Panetes". La plaza de Huesca era una placica al lado de la plaza del Pilar, entre las calles de la Zuda (izquierda), de la Regla (donde los adoquines), de Agustinos (enfrente a â”śÂ®sta), y del Fin (derecha). Esta â”śâ•‘ltima comunicaba, por medio de un antiguo trenque, con el paseo de la ribera. Al fondo, otra puerta daba entrada al recinto donde se levantaba San Juan de los Panetes. La clase social que aquâ”śÂˇ vivâ”śÂˇa era sustancialmente diferente a la de la vecina plaza del Pilar, como reflejan los tipos y situaciones que la imagen captura, impensables apenas 100 metros hacia la derecha, en el "salâ”śâ”‚n de la ciudad". Es uno de esos dâ”śÂˇas en que la sombra apetece mâ”śĂ­s que la solana, y un cabrero ordeâ”śâ–’a a una chiva del rebaâ”śâ–’o, mientras unos chavales callejean a su gusto. Estos â”śĂ­rboles no eran tampoco como los de la plaza del Pilar. Fuente visual: "Miguel y Gabriel Faci. Fotâ”śâ”‚grafos fundadores de la Real Sociedad Fotogrâ”śĂ­fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaciâ”śâ”‚n Provincial de Zaragoza, 1999.', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65722900, -0.88085200, '0101000020E6100000D8B79388F02FECBFCC7D721420D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15789998832.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15789998832.webp', 'https://www.flickr.com/photos/zaragozaantigua/15789998832/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24669, 'Murallas romanas 1987', 'Luis Mâ”śÂˇnguez. 1987. Desde un â”śâ”‚culo de la octogonal, barroca, inclinada y enladrillada torre de San Juan de los Panetes, una insâ”śâ”‚lita mirada sobre el entorno. Inmediato, el incontingente aparcamiento. A la izquierda, el salvado Mercado Central. Enfrente, los recios lienzos de la muralla de piedra, y el vacâ”śÂˇo dejado en su pedestal por el casi semoviente Câ”śÂ®sar Augusto primaportado y mussolâ”śÂˇniano. Al fondo, la rotunda fachada de la original "Poblaciâ”śâ”‚n" (San Pablo), y su inmemorial acceso por la calle de Predicadores. Plagado de publicidad comercial, un enorme solar esquinado a la avenida y a la calle Ben Aire, en modo espera.', 1987, 1987, 1987, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65723400, -0.88186700, '0101000020E6100000027E8D244138ECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15834431621.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15834431621.webp', 'https://www.flickr.com/photos/zaragozaantigua/15834431621/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24670, 'San Juan de los Panetes 1927', 'Imagen a cierta altura de la octogonal y barroca torre de San Juan de los Panetes, emergente en el entorno de callejas y recovecos que caracterizaba esta zonba, junto a la plaza de Huesca, desde la que se accedâ”śÂˇa por la calle de Agustinos (izquierda), tras cruzar un pequeâ”śâ–’o arco de medio punto. Esta torre se apoyaba en construcciones que se le habâ”śÂˇan ido anexando en el transcurso de los siglos. La imagen estâ”śĂ­ tomada, precisamente, desde la altura de una de estas viviendas, la nâ”¬â•‘ 35 recayente al paseo del Ebro. A la derecha destaca por su altura el tejado a doble vertiente de la nave central de la iglesia, y algunos de sus contrafuertes de refuerzo. Enfrente, viviendas del nâ”¬â•‘ 11 de la calle de La Zuda y dependencias del, hasta hace poco, antiguo convento de las Adoratrices. El Torreâ”śâ”‚n de la Zuda queda un poco hacia la derecha, y, como las murallas romanas, rodeado de un compost de edificaciones. Cuando unos aâ”śâ–’os despuâ”śÂ®s, se inicien obras para abrir calles y despejar la zona, la torre presentarâ”śĂ­ graves problemas de estabilidad por la merma de sus tradicionales apoyos. El Ayuntamiento del momento estaba decidido a su derribo para construir un mercado en el lugar, pero mientras tanto, se proclamâ”śâ”‚ la Segunda Repâ”śâ•‘blica, y el nuevo Gobierno declarâ”śâ”‚ el templo como Monumento Nacional. Fuente visual: Instituto Amatller de Arte Hispâ”śĂ­nico (Arxiu Mas). Fuente textual: Ascensiâ”śâ”‚n Hernâ”śĂ­ndez Martâ”śÂˇnez, "De restauraciones, demoliciones y otros debates sobre el patrimonio monumental zaragozano del siglo XX", IFC, 2008.', 1927, 1927, 1927, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15893540992.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15893540992.webp', 'https://www.flickr.com/photos/zaragozaantigua/15893540992/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24105, 'Jardâ”śÂˇn de Invierno 1960', 'Imagen capturada en el "auditorium" (sic) del Jardâ”śÂˇn de Invierno en el parque de Primo de Rivera durante la solemne celebraciâ”śâ”‚n del aniversario 55 de la "coronaciâ”śâ”‚n canâ”śâ”‚nica de la Virgen del Pilar" que, a iniciativa del Ayuntamiento, consistiâ”śâ”‚ en una misa con rito pontifical oficiada por el arzobispo Casimiro Morcillo. Al fondo, escenario donde se instalâ”śâ”‚ el altar con la imagen procesional en plata de la Virgen, y una gran cruz de cinco metros de altura iluminada por reflectores que presidâ”śÂˇa la ceremonia. A la derecha, banderas de Acciâ”śâ”‚n Catâ”śâ”‚lica, y a la izquierda, representaciâ”śâ”‚n de seminaristas. Sobre el firme, espacio para el pâ”śâ•‘blico asistente, al frente del cual se colocaron bancos para las autoridades (entre ellas la Corporaciâ”śâ”‚n municipal encabezada por el alcalde Luis Gâ”śâ”‚mez Laguna; la Corporaciâ”śâ”‚n provincial con el presidente Antonio Zubiri Vidal; el gobernador civil y jefe provincial del "Movimiento" Josâ”śÂ® Manuel Pardo de Santayana; y autoridades militares encabezadas por el capitâ”śĂ­n general Manuel Baturone Colombo), ademâ”śĂ­s de mil sillas de pago. Este evento comenzâ”śâ”‚ a las 20:00h. y terminâ”śâ”‚ a las 22:00h. del dâ”śÂˇa 20 de mayo de ese aâ”śâ–’o.', 1960, 1960, 1960, 'Anos 60', 'UNIVERSIDAD', 41.63175500, -0.89290700, '0101000020E6100000B7D26BB3B192ECBFD00A0C59DDD04440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51653859433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51653859433.webp', 'https://www.flickr.com/photos/zaragozaantigua/51653859433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24671, 'Paseo del Ebro c.1900', 'Tener el Pilar a las espaldas, tras el Callejâ”śâ”‚n del Retiro Alto, tampoco es mala cosa a la hora de capturar instantâ”śĂ­neas en Zaragoza, en este caso, desde altura, y mirando hacia el Puente del Ferrocarril (al fondo). A la derecha, Macanaz-Ranillas, con un brazal de la acequia de Juslibol desaguando al Ebro. En el despejado Paseo, una unidad de la Lâ”śÂˇnea de Circunvalaciâ”śâ”‚n, a propulsiâ”śâ”‚n de sangre, dirigiâ”śÂ®ndose hacia la mitad de su periplo a lo Sâ”śÂˇsifo. Un jinete solitario completa el trâ”śĂ­fico rodado en velocidad. A la izquierda, junto a la Puerta del Fin, un destacado concesionario de â”śÂ®quidos, mulos, y carros, con alto y animado volumen comercial. Al otro lado de la calle del Fin, el entramado de calles que configura las traseras de la plaza de Huesca: Agustinos, de la Regla, de la Zuda, de las Flores... un espacio urbano complejo e irrepetible, con elementos desaparecidos, como el Colegio de los Agustinos Descalzos de San Nicolâ”śĂ­s de Tolentino, la iglesia de San Antâ”śâ”‚n, el Hospital de San Juan de los Panetes... ademâ”śĂ­s de todas las casas donde los prostituidores desfogâ”śĂ­banse a sus anchas, a cambio de unos dineros, en otro tipo de comercio de la carne. Superviven la reorientada, modificada y barroca torre e iglesia de San Juan de los Panetes, y el torreâ”śâ”‚n de la Zuda, que sobresale tras la iglesia, por encima de vestigios de muralla romana. Fuente visual: AHPZ, Archivo Coyne, ca. 1900', 1900, 1900, 1900, 'Anos 1900', 'CASCO HISTâ”śĂ´RICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16451696592.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16451696592.webp', 'https://www.flickr.com/photos/zaragozaantigua/16451696592/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24672, 'Plaza del Mercado 1975', 'Desde el Torreâ”śâ”‚n de la Zuda, vista de la plaza de Lanuza. Estamos en la linde entre la parroquia del Pilar, a la izquierda, y la de San Pablo, a la derecha. Al fondo, la câ”śâ•‘pula de Santiago el Mayor y siluetas de los monstruos edilicios que van surgiendo como edificios singulares y actuaciones aisladas. En primer tâ”śÂ®rmino, las murallas romanas, seguidas del Mercado Central, y de la manzana entre las calles de Cerdâ”śĂ­n y de las Escuelas Pâ”śÂˇas.', 1975, 1975, 1975, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65752400, -0.88159400, '0101000020E6100000C231CB9E0436ECBFE52A16BF29D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19025863396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19025863396.webp', 'https://www.flickr.com/photos/zaragozaantigua/19025863396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24673, 'Puerta del Fin 1922', 'Dibujo de Dâ”śÂˇaz Domâ”śÂˇnguez del rincâ”śâ”‚n del paseo del Ebro de Zaragoza a la altura de la calle del Fin (tras la garita del fielato). Esta calle era uno de los accesos a la ciudad, cerrado con su puerta, que daba nombre a toda la explanada, utilizada como feria del ganado. El edificio donde se encuentra el negocio del veterinario Remacha habâ”śÂˇa sido Colegio de los Agustinos, vulgo Agustinicos. Al fondo, la torreta de la câ”śâ•‘pula de San Juan de los Panetes. Fuente: La Cadiera 114, 1957.', 1922, 1922, 1922, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65749900, -0.87979600, '0101000020E61000000ADAE4F04927ECBF8C135FED28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20057942382.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20057942382.webp', 'https://www.flickr.com/photos/zaragozaantigua/20057942382/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24674, 'San Juan de los Panetes 1988', 'Foto Eduardo Zamarripa, 1988. Vista aâ”śÂ®rea del torreâ”śâ”‚n de la Zuda y la iglesia de San Juan de los Panetes de Zaragoza en 1988. Fuente: Aragâ”śâ”‚n desde el aire, Ministerio de Defensa, 1988.', 1988, 1988, 1988, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65734500, -0.88122100, '0101000020E6100000A08CF161F632ECBF359886E123D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20325163741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20325163741.webp', 'https://www.flickr.com/photos/zaragozaantigua/20325163741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24677, 'Paseo del Ebro 1926', 'Imagen del paseo del Ebro en la zona cercana a las traseras del convento de San Juan de los Panetes, entre las calles de Antonio Pâ”śÂ®rez, y la del Fin, con notable proliferaciâ”śâ”‚n de caballerâ”śÂˇas y carros. Despunta la linterna y el â”śĂ­bside principal de la barroca iglesia de San Juan. Al fondo, el chaflâ”śĂ­n del colegio Valentâ”śÂˇn Zabala. Fuente visual: Miguel Marâ”śÂˇn Chivite, AMZ', 1926, 1926, 1926, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65759400, -0.88028000, '0101000020E610000008556AF6402BECBFDE054A0A2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24505950831.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24505950831.webp', 'https://www.flickr.com/photos/zaragozaantigua/24505950831/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24679, 'Cruz de los caâ”śÂˇdos 1971', 'Foto: Iâ”śâ–’aki Urbez. Vista de la Cruz de los caâ”śÂˇdos y el entorno de San Juan de los Panetes, desde la torre de San Francisco de Borja del Pilar. Fuente: www.facebook.com/groups/fotosantiguasdezaragoza/permalink...', 1971, 1971, 1971, 'Anos 70', 'CASCO HISTâ”śĂ´RICO', 41.65726000, -0.88086300, '0101000020E6100000D234289A0730ECBF077C7E1821D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29653584062.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29653584062.webp', 'https://www.flickr.com/photos/zaragozaantigua/29653584062/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24680, 'San Juan de los Panetes c.1925', 'Imagen capturada desde la margen izquierda del râ”śÂˇo Ebro, en la arboleda de Macanaz, frente a la iglesia de San Juan de los Panetes y la embocadura a la calle de Antonio Pâ”śÂ®rez. A la derecha, asoma levemente el torreâ”śâ”‚n de la Zuda. Destacan las escaleras de acceso a las barcas que daban servicio de paso en este tramo del râ”śÂˇo. El gran agujero abovedado en el pretil recuerda el antiguo desagâ”śâ•ťe que aquâ”śÂˇ vertâ”śÂˇa desde la antigua plaza del Mercado. Fuente: fotografâ”śÂˇa de Claudi Carbonell Flo, en www.museunacional.cat/', 1925, 1925, 1925, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30134489963.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30134489963.webp', 'https://www.flickr.com/photos/zaragozaantigua/30134489963/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24683, 'La Zuda 1882', 'Grabado con diseâ”śâ–’o de Bernardo Rico, basado en una fotografâ”śÂˇa de Jean Laurent capturada en la calle de Antonio Pâ”śÂ®rez, y titulado "Zaragoza.-El torreâ”śâ”‚n de la Azuda donde se firmâ”śâ”‚ la rendiciâ”śâ”‚n de la ciudad â”śĂ­ Don Alfonso I â”¬Â˝El Batalladorâ”¬â•— (1118)". Fuente visual: La Ilustraciâ”śâ”‚n espaâ”śâ–’ola y americana (1882)', 1882, 1882, 1882, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34638029461.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34638029461.webp', 'https://www.flickr.com/photos/zaragozaantigua/34638029461/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24685, 'Torreâ”śâ”‚n de la Zuda 1890', '"Torreâ”śâ”‚n del Palacio Real de la Azuda donde, al tomar Zaragoza, se aposentâ”śâ”‚ Alfonso el Batallador". Ilustraciâ”śâ”‚n de Ambrosio del Ruste, 1948, basada en una fotografâ”śÂˇa de 1890. Fuente: "Conquista de Zaragoza por Don Alfonso I el Batallador", La Cadiera, 1948.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65756000, -0.88163100, '0101000020E61000000C7904375236ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41407425642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41407425642.webp', 'https://www.flickr.com/photos/zaragozaantigua/41407425642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24686, 'Murallas romanas ca. 2005', 'Vista desde el torreâ”śâ”‚n de la Zuda de los restos de las murallas romanas, con la calle homâ”śâ”‚nima a la izquierda y la avenida de Câ”śÂ®sar Augusto a la derecha. Se estâ”śĂ­ procediendo a su restauraciâ”śâ”‚n, que incluye la retirada del pedestal con dos columnas que sostuvo la estatua de Câ”śÂ®sar Augusto. Entre 2012 y 2013, esta zona se verâ”śĂ­ modificada por el paso del tranvâ”śÂˇa y la retirada de los arcos "Alegorâ”śÂˇa de la Puerta de la Paz", entre las murallas y el Mercado Central. Al fondo, la câ”śâ•‘pula de la iglesia de Santiago el Mayor. Fuente: Archivo Antonio Tausiet.', 2005, 2005, 2005, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65718500, -0.88192100, '0101000020E6100000CEFA9463B238ECBFFC3559A31ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41597324550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41597324550.webp', 'https://www.flickr.com/photos/zaragozaantigua/41597324550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24687, 'Plaza de Huesca 1914', 'Foto: Serrano Sancho. "Hundimiento de una casa en Zaragoza. Estado en que quedâ”śâ”‚ la casa de la plaza de Huesca que se derrumbâ”śâ”‚ el miâ”śÂ®rcoles â”śâ•‘ltimo", 28 de enero de 1914. Al fondo, la câ”śâ•‘pula de la torre de San Juan de los Panetes. Fuente: Diario ABC, 31-1-1914.', 1914, 1914, 1914, 'Anos 10', 'CASCO HISTâ”śĂ´RICO', 41.65734300, -0.88091400, '0101000020E61000005AD5928E7230ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/43256261372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/43256261372.webp', 'https://www.flickr.com/photos/zaragozaantigua/43256261372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24688, 'Avenida de Câ”śÂ®sar Augusto 1999', 'La avenida de Câ”śÂ®sar Augusto, en su tramo adyacente a las Murallas Romanas, entre el paseo de Echegaray y Caballero y el Mercado Central. A la izquierda, el Torreâ”śâ”‚n de la Zuda, y tras el lienzo de muralla, la iglesia de San Juan de los Panetes. Este entorno, olivos incluidos, serâ”śĂ­ trocado en otro distinto con el paso de la nueva lâ”śÂˇnea de tranvâ”śÂˇa en 2013.', 1999, 1999, 1999, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65718500, -0.88192100, '0101000020E6100000CEFA9463B238ECBFFC3559A31ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50210619061.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50210619061.webp', 'https://www.flickr.com/photos/zaragozaantigua/50210619061/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24689, 'San Juan de los Panetes 1990', 'En el proyecto de rehabilitaciâ”śâ”‚n y embellecimiento de la plaza del Pilar, cuyas obras comenzaron tras las Fiestas del Pilar de 1990, estaba incluido el desmantelamiento del "Monumento a los hâ”śÂ®roes y mâ”śĂ­rtires de Zaragoza caâ”śÂˇdos en la Cruzada de Liberaciâ”śâ”‚n 1936-1939", que serâ”śÂˇa trasladado al cementerio catâ”śâ”‚lico de Torrero y sustituido por una fuente alusiva a la "Hispanidad". En la imagen, montaje de los andamios previo al desmontaje de este monumental cenotafio terminado en 1954, quince aâ”śâ–’os despuâ”śÂ®s del oficial final de la guerra, como muestra de que el râ”śÂ®gimen franquista no pasaba pâ”śĂ­gina ni a sus orâ”śÂˇgenes ni a sus sâ”śÂˇmbolos fundacionales, ni a la memoria de sus muertos. Este trâ”śĂ­nsito edilicio apenas suscitâ”śâ”‚ polâ”śÂ®mica o resiliencia social.', 1990, 1990, 1990, 'Anos 90', 'CASCO HISTâ”śĂ´RICO', 41.65725800, -0.88091200, '0101000020E61000002DEDD45C6E30ECBF6684B70721D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50374895517.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50374895517.webp', 'https://www.flickr.com/photos/zaragozaantigua/50374895517/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23749, 'Torre de Santa Engracia 1972', 'Torre de Santa Engracia era una finca del barrio rural de Movera que fue adquirida en 1970 por el Ayuntamiento, mediante permuta con la papelera La Montaâ”śâ–’anesa. El edificio responde a la tipologâ”śÂˇa de las agrâ”śÂˇcolas torres de la periferia de Zaragoza, y estâ”śĂ­ datada en el siglo XVII, cuando era propiedad del monasterio de Santa Engracia. En el siglo XIX fue desamortizada y muy modificada. Desde 2015 acoge a la Escuela Agrâ”śÂˇcola Municipal Km 0.', 1972, 1972, 1972, 'Anos 70', NULL, 41.64234700, -0.80543500, '0101000020E610000067B8019F1FC6E9BF84D72E6D38D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15795238915.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15795238915.webp', 'https://www.flickr.com/photos/zaragozaantigua/15795238915/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24692, 'Torreâ”śâ”‚n de la Zuda c.1885', 'Imagen capturada desde la altura del inmueble del nâ”¬â•‘ 25 de la calle de Antonio Pâ”śÂ®rez y centrada en el Torreâ”śâ”‚n de la Zuda reciâ”śÂ®n restaurado y al que se ha incorporado una nueva cubierta a cuatro aguas proyectada por el arquitecto municipal Ricardo Magdalena. Este torreâ”śâ”‚n despunta de las instalaciones del antiguo palacio de la Castellanâ”śÂˇa de Amposta de san Juan de Jerusalâ”śÂ®n, desde unos pocos aâ”śâ–’os antes convertido en convento de las Madres Adoratrices, y con varias casas adosadas recayentes al lado de los pares de la calle de Antonio Pâ”śÂ®rez. Tras el torreâ”śâ”‚n y a la izquierda aparece la iglesia de san Juan de los Panetes, y a la derecha la antigua torre inacabada de Santiago del templo del Pilar. Mâ”śĂ­s al fondo, la barroca torre de la Seo.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65755500, -0.88170600, '0101000020E6100000B5FB5580EF36ECBF202922C32AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52286836398.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52286836398.webp', 'https://www.flickr.com/photos/zaragozaantigua/52286836398/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24865, 'P.â”¬â•‘ del Ebro 1929', 'Imagen centrada en el antiguo paseo del Ebro, en la zona comprendida entre la calle del Fin y la iglesia de San Juan de los Panetes, al fondo, con el firme pendiente de embellecimiento, y notable trâ”śĂ­fico de vehâ”śÂˇculos tirados por caballerâ”śÂˇa. Este tramo de la antigua lâ”śÂˇnea tranviaria de Circunvalaciâ”śâ”‚n estaba suprimido desde 1925, cuando entrâ”śâ”‚ en servicio la lâ”śÂˇnea del Ayuntamiento. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CASCO HISTâ”śĂ´RICO', 41.65750100, -0.87988100, '0101000020E610000097E5EB32FC27ECBF2D0B26FE28D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/35307218056.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/35307218056.webp', 'https://www.flickr.com/photos/zaragozaantigua/35307218056/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25131, 'Calle del Fin aâ”śâ–’os 30', 'Acuarela de Ambrosio Ruste. Portada de la iglesia del antiguo Convento y colegio de San Nicolâ”śĂ­s de Tolentino de los Agustinos, situado en la calle del Fin, uno de los postigos abiertos en la antigua muralla romana, que anteriormente fue conocido como "Postigo de Montaner", y luego "de la madera", por el trâ”śĂ­fago de este material desde la ribera del Ebro hacia el interior de la ciudad. Este colegio fue abierto en 1605, y tenâ”śÂˇa una pequeâ”śâ–’a iglesia que conectaba con el inmediato palacio de los Ayerbe, sus grandes financiadores. El colegio dio nombre ("Agustinos") a la calle que desde la plaza del Pilar conducâ”śÂˇa a San Juan de los Panetes. Como todas las demâ”śĂ­s construcciones de la zona, fueran palacios, colegios, o sencillas viviendas, fue arrasado cuando la plaza del Pilar fue retro-evolucionada del barroco, al nacional-catolicismo. En la imagen, la sencilla portada de la iglesia del colegio-convento. Destaca el escudo nobiliario en altorrelieve del barâ”śâ”‚n don Hugo de Urriâ”śÂ®s y su mujer, doâ”śâ–’a Beatriz de Cardona y Requesens, patrocinadores del colegio. Por la izquierda se accedâ”śÂˇa a la "puerta del Fin" que daba acceso al paseo de la ribera. Por la derecha, a la calle Agustinos. Fuente visual: Lâ”śĂ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65722600, -0.87978600, '0101000020E610000026512FF83427ECBF5B0A48FB1FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18546963160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18546963160.webp', 'https://www.flickr.com/photos/zaragozaantigua/18546963160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25153, 'Torreâ”śâ”‚n de la Zuda aâ”śâ–’os 30', 'Acuarela de Ambrosio Ruste representando el torreâ”śâ”‚n de la Zuda, con la iglesia de San Juan de los Panetes a la derecha. Fuente: Lâ”śĂ­minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HISTâ”śĂ´RICO', 41.65756000, -0.88160100, '0101000020E610000061DEE34C1336ECBF319413ED2AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31627244013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31627244013.webp', 'https://www.flickr.com/photos/zaragozaantigua/31627244013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25406, 'Pasarela sobre el Ebro c.1945', 'Aguas arriba del puente de Piedra, estuvo en servicio esta pasarela peatonal sobre el Ebro, con taquillas en ambos mâ”śĂ­rgenes, desde el 25 de febrero de 1941 hasta la inauguraciâ”śâ”‚n del puente de Santiago en 1967. Conocida como pasarela de Macanaz.', 1945, 1945, 1945, 'Anos 40', 'CASCO HISTâ”śĂ´RICO', 41.65787500, -0.88078600, '0101000020E6100000FBC9181F662FECBF91ED7C3F35D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14899757335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14899757335.webp', 'https://www.flickr.com/photos/zaragozaantigua/14899757335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25419, 'Echegaray y Caballero 1956', 'Foto Josâ”śÂ® Antonio Duce, 1956. Dâ”śÂˇa de niebla en el Paseo de Echegaray y Caballero de Zaragoza, junto al Ebro, a la altura de la pasarela de Macanaz (al fondo). Fuente: www.rafaelcastillejo.com/zaraduce.htm', 1956, 1956, 1956, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65771500, -0.88075300, '0101000020E61000000D535BEA202FECBF598B4F0130D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15842183336.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15842183336.webp', 'https://www.flickr.com/photos/zaragozaantigua/15842183336/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25453, 'Pasarela de Macanaz 1950', 'Imagen estival centrada en la pasarela peatonal tendida sobre el râ”śÂˇo Ebro en 1941, tambiâ”śÂ®n conocida como de Macanaz, flanqueada por los escalonados descensos hacia los embarcaderos, y con una vista del antiguo colector de la Triperâ”śÂˇa. La escena se ha capturado desde uno de los embarcaderos recreativos de la Margen Izquierda. El fondo edilicio viene determinado por el templo del Pilar con sus dos torres, como desde principios de siglo, la gran Hospederâ”śÂˇa del Pilar de la Sociedad Angâ”śÂ®lica del Sagrado Corazâ”śâ”‚n de Jesâ”śâ•‘s, el nuevo convento de las Hermanas Misioneras Eucarâ”śÂˇsticas de Nazareth, adosado a la iglesia de San Juan de los Panetes, y el Grupo Escolar de Valentâ”śÂˇn Zabala, sobre el que emerge el Torreâ”śâ”‚n de la Zuda. Fuente visual: AMZ', 1950, 1950, 1950, 'Anos 50', 'CASCO HISTâ”śĂ´RICO', 41.65801400, -0.88160800, '0101000020E6100000008BFCFA2136ECBFB32781CD39D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39994558783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39994558783.webp', 'https://www.flickr.com/photos/zaragozaantigua/39994558783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25554, 'Puente de Santiago 2012', 'Obras para la segunda fase de la lâ”śÂˇnea 1 del tranvâ”śÂˇa, a su paso por el puente de Santiago. Al fondo, la margen izquierda del Ebro. Fuente: www.skyscrapercity.com/', 2012, 2012, 2012, 'Siglo XXI', 'CASCO HISTâ”śĂ´RICO', 41.65821000, -0.88163300, '0101000020E61000003961C2685636ECBF38F3AB3940D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24825966856.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24825966856.webp', 'https://www.flickr.com/photos/zaragozaantigua/24825966856/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20894, 'Puerto fluvial siglo I', 'Maqueta del edificio de acceso del puerto fluvial de Caesaraugusta, siglo I. Al derribar las casas de la plaza de San Bruno en 1989 para construir las actuales viviendas de protecciâ”śâ”‚n oficial, se descubrieron los vestigios de una edificaciâ”śâ”‚n al nordeste del foro. Consta de una serie de vanos pertenecientes a una fachada de arquerâ”śÂˇas orientada hacia el râ”śÂˇo Ebro, por las que se alcanzaba un vestâ”śÂˇbulo y desde â”śÂ®ste una escalinata que comunicaba los muelles del puerto fluvial con la plaza del foro. Hoy es un museo visitable, en la plaza de San Bruno 8. Fuente: www.zaragoza.es/ciudad/museos/es/puerto', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65518900, -0.87460400, '0101000020E6100000D36C1E87C1FCEBBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19783359583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19783359583.webp', 'https://www.flickr.com/photos/zaragozaantigua/19783359583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20895, 'Puerto fluvial 1989', 'Estructura del puerto fluvial romano del siglo I en el entorno de la plaza de San Bruno de Zaragoza. Al fondo, la calle Arcedianos. Fuente: dp-foto.blogspot.com', 1989, 1989, 1989, 'Anos 80', 'CASCO HISTâ”śĂ´RICO', 41.65518900, -0.87460400, '0101000020E6100000D36C1E87C1FCEBBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20082409184.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20082409184.webp', 'https://www.flickr.com/photos/zaragozaantigua/20082409184/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20903, 'Puerto fluvial siglo I', 'Recreaciâ”śâ”‚n infogrâ”śĂ­fica del puerto fluvial de Caesaraugusta y su entorno junto al râ”śÂˇo Ebro. A la derecha, el puente romano. Tras el gran edificio del puerto, el foro con su templo.', 50, NULL, 99, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65592200, -0.87462000, '0101000020E61000003EAE0D15E3FCEBBF0B5D8940F5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54170714151.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54170714151.webp', 'https://www.flickr.com/photos/zaragozaantigua/54170714151/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20925, 'Casa Diputados Reino 1539', 'Dibujo de Valentâ”śÂˇn Carderera y Solano, del "patinejo" de la antigua Casa hospedaje de los Diputados del Reino de Aragâ”śâ”‚n, en la calle del General del Reino, un palacio del siglo XVI demolido parcialmente en 1863-64, cuando el patio fue desmontado, y completamente en la dâ”śÂ®cada de los aâ”śâ–’os 40 del siglo XX, cuando el entorno de la Seo, como la calle de Palafox, fue "reordenado". Este palacio habâ”śÂˇa sido adquirido como residencia de los Diputados del Reino que no vivâ”śÂˇan en Zaragoza, mientras su estancia en la ciudad. El dibujo estâ”śĂ­ tomado al natural, y datado en torno a 1860, poco antes del desmontaje del patio, aunque el autor parece situarlo en "1539", fecha de la talla del patio por Renâ”śÂ® Trayanus, introduciendo para ambientar dos ficcionados personajes de esa â”śÂ®poca. Cuatro columnas, cuatro pilastras, y algunos fragmentos del arquitrabe, en alabastro ensuciado, perduran en el Museo de Zaragoza, recompuestos desordenadamente. Fuente visual: ceres.mcu.es/', 1539, 1539, 1539, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65440600, -0.87472000, '0101000020E6100000210725CCB4FDEBBF31276893C3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22357296016.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22357296016.webp', 'https://www.flickr.com/photos/zaragozaantigua/22357296016/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
