INSERT INTO public.photos VALUES (20985, 'Puente de Tablas 1803', '"Plan y elevaciâ”śâ”‚n general y perfiles por mayor del puente de madera proyectado sobre el râ”śÂˇo Ebro en el mismo sitio que estaba el antiguo para paso de la carretera real de Madrid a Barcelona", Fernando Martâ”śÂˇnez Corcâ”śÂˇn, Zaragoza, 13 de junio de 1803. La avenida del Ebro del 10 de junio de 1801 daâ”śâ–’â”śâ”‚ por enâ”śÂ®sima vez el Puente de Tablas de Zaragoza, que habâ”śÂˇa sido reconstruido tras la riada del 23 de junio de 1775. En 1803 se proyecta de nuevo, aprobâ”śĂ­ndose la obra al aâ”śâ–’o siguiente, aunque no se llevâ”śâ”‚ a cabo. En 1895 se inaugurâ”śâ”‚ en sus inmediaciones el Puente del Pilar o de Hierro. Fuente visual: Fondo del Intendente. Secciâ”śâ”‚n de Obras Municipales. Diputaciâ”śâ”‚n Provincial de Zaragoza.', 1803, 1803, 1803, 'Siglo XIX', 'CASCO HISTâ”śĂ´RICO', 41.65580700, -0.87212500, '0101000020E61000009CC420B072E8EBBF73BED87BF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24088066161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24088066161.webp', 'https://www.flickr.com/photos/zaragozaantigua/24088066161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
